// ================= 1. setState тАФ for widget-local state =================
class Counter1 extends StatefulWidget {
  const Counter1({super.key});
  @override State<Counter1> createState() => _Counter1State();
}
class _Counter1State extends State<Counter1> {
  int _count = 0;
  @override
  Widget build(BuildContext context) => Column(children: [
    Text('$_count'),
    FilledButton(onPressed: () => setState(() => _count++), child: const Text('+1')),
  ]);
}

// ================= 2. Provider тАФ legacy but still common ================
// pubspec: provider: ^6.1
import 'package:provider/provider.dart' as p;

class CounterModel extends ChangeNotifier {
  int count = 0;
  void increment() { count++; notifyListeners(); }
}

void main2() => runApp(p.ChangeNotifierProvider(
  create: (_) => CounterModel(),
  child: const MaterialApp(home: _Counter2Screen()),
));

class _Counter2Screen extends StatelessWidget {
  const _Counter2Screen();
  @override
  Widget build(BuildContext c) {
    final model = c.watch<CounterModel>();
    return Column(children: [
      Text('${model.count}'),
      FilledButton(onPressed: c.read<CounterModel>().increment, child: const Text('+1')),
    ]);
  }
}

// ================= 3. Riverpod тАФ modern default ==========================
// pubspec: flutter_riverpod: ^2.5
import 'package:flutter_riverpod/flutter_riverpod.dart';

final counterProvider = NotifierProvider<CounterNotifier, int>(CounterNotifier.new);

class CounterNotifier extends Notifier<int> {
  @override int build() => 0;
  void increment() => state++;
}

void main3() => runApp(const ProviderScope(child: MaterialApp(home: _Counter3Screen())));

class _Counter3Screen extends ConsumerWidget {
  const _Counter3Screen();
  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final count = ref.watch(counterProvider);
    return Column(children: [
      Text('$count'),
      FilledButton(
        onPressed: () => ref.read(counterProvider.notifier).increment(),
        child: const Text('+1'),
      ),
    ]);
  }
}

// Notice how Riverpod's counterProvider is a TOP-LEVEL final тАФ no BuildContext
// needed to access it, easy to test, and the widget only rebuilds when `state`
// changes. That's the shape of modern Flutter state.
